class RateLimiter:
    """Thread-safe in-memory rate limiter using sliding window."""
    
    def __init__(self):
        self._requests = defaultdict(list)
        self._lock = Lock()
    
    def is_rate_limited(self, client_id, max_requests, window_seconds):
        """Check if client has exceeded rate limit."""
        now = time.time()
        with self._lock:
            # Clean old entries
            self._requests[client_id] = [
                ts for ts in self._requests[client_id]
                if now - ts < window_seconds
            ]
            if len(self._requests[client_id]) >= max_requests:
                return True
            self._requests[client_id].append(now)
            return False
    
    def get_remaining(self, client_id, max_requests, window_seconds):
        """Get remaining requests for client."""
        now = time.time()
        with self._lock:
            active = [
                ts for ts in self._requests.get(client_id, [])
                if now - ts < window_seconds
            ]
            return max(0, max_requests - len(active))


rate_limiter = RateLimiter()


