class QueryValidator:
    """Validates GraphQL queries against security policies."""
    
    def __init__(self, config):
        self.config = config
    
    def validate(self, query):
        """Run all validation checks on the query. Returns (is_valid, error_message)."""
        if not query or not isinstance(query, str):
            return False, "Invalid or empty query"
        
        # Check query size
        if len(query) > self.config.GRAPHQL_MAX_QUERY_SIZE:
            return False, f"Query exceeds maximum size of {self.config.GRAPHQL_MAX_QUERY_SIZE} bytes"
        
        # Block introspection in production
        if not self.config.GRAPHQL_INTROSPECTION_ENABLED:
            if self._contains_introspection(query):
                return False, "Introspection is disabled"
        
        # Check query depth
        depth = self._calculate_depth(query)
        if depth > self.config.GRAPHQL_MAX_DEPTH:
            return False, f"Query depth {depth} exceeds maximum allowed depth of {self.config.GRAPHQL_MAX_DEPTH}"
        
        # Check aliases count
        alias_count = self._count_aliases(query)
        if alias_count > self.config.GRAPHQL_MAX_ALIASES:
            return False, f"Query contains {alias_count} aliases, exceeding maximum of {self.config.GRAPHQL_MAX_ALIASES}"
        
        # Check directive count (directive overloading attack)
        directive_count = self._count_directives(query)
        if directive_count > self.config.GRAPHQL_MAX_DIRECTIVES:
            return False, f"Query contains {directive_count} directives, exceeding maximum of {self.config.GRAPHQL_MAX_DIRECTIVES}"
        
        # Check for batch query abuse (multiple top-level operations)
        if self._is_batch_abuse(query):
            return False, "Batch query limit exceeded"
        
        return True, None
    
    def _contains_introspection(self, query):
        """Detect introspection queries."""
        introspection_patterns = ['__schema', '__type', '__typename']
        query_lower = query.lower()
        # Allow __typename as it's commonly used for cache, but block __schema and __type
        return '__schema' in query_lower or '__type(' in query_lower or '__type ' in query_lower
    
    def _calculate_depth(self, query):
        """Calculate the nesting depth of a GraphQL query."""
        max_depth = 0
        current_depth = 0
        in_string = False
        
        for char in query:
            if char == '"':
                in_string = not in_string
            if in_string:
                continue
            if char == '{':
                current_depth += 1
                max_depth = max(max_depth, current_depth)
            elif char == '}':
                current_depth -= 1
        
        return max_depth
    
    def _count_aliases(self, query):
        """Count the number of aliases in the query."""
        # Aliases follow the pattern: aliasName: fieldName
        alias_pattern = re.compile(r'\b\w+\s*:\s*\w+\s*[\({]')
        # Exclude argument patterns like (id: "1")
        # A more precise approach: look for aliases outside of parentheses
        count = 0
        paren_depth = 0
        lines = query.split('\n')
        for line in lines:
            stripped = line.strip()
            # Skip lines that are inside argument lists
            for char in stripped:
                if char == '(':
                    paren_depth += 1
                elif char == ')':
                    paren_depth -= 1
            if paren_depth == 0:
                # Look for alias pattern: word colon word
                aliases = re.findall(r'^\s*(\w+)\s*:\s*(\w+)', stripped)
                for alias_name, field_name in aliases:
                    # Filter out known argument-like patterns
                    if field_name not in ('true', 'false', 'null'):
                        count += 1
        return count
    
    def _count_directives(self, query):
        """Count directives (@ prefixed) in the query."""
        return len(re.findall(r'@\w+', query))
    
    def _is_batch_abuse(self, query):
        """Check for excessive batch operations."""
        # Count top-level query/mutation operations
        operations = re.findall(r'\b(query|mutation|subscription)\b', query, re.IGNORECASE)
        return len(operations) > 3


class ComplexityAnalyzer:
    """Analyzes and limits query complexity based on field weights."""
    
    # Field complexity weights
    FIELD_WEIGHTS = {
        'products': 5,
        'allProducts': 10,
        'productsByCategory': 8,
        'reviews': 3,
        'allReviews': 8,
        'reviewsByProduct': 5,
        'categories': 2,
        'allCategories': 5,
        'averageRating': 2,
    }
    DEFAULT_WEIGHT = 1
    
    @classmethod
    def calculate_complexity(cls, query):
        """Estimate query complexity based on field weights."""
        total = 0
        for field, weight in cls.FIELD_WEIGHTS.items():
            # Count occurrences of each weighted field
            count = len(re.findall(r'\b' + field + r'\b', query))
            total += count * weight
        
        # Add base complexity for depth
        depth = 0
        current = 0
        for char in query:
            if char == '{':
                current += 1
                depth = max(depth, current)
            elif char == '}':
                current -= 1
        total += depth * 2
        
        return total


