class InputSanitizer:
    """Sanitizes and validates user inputs."""
    
    @staticmethod
    def sanitize_string(value, max_length=200):
        """Sanitize a string input."""
        if not isinstance(value, str):
            return None
        # Truncate
        value = value[:max_length]
        # Remove null bytes
        value = value.replace('\x00', '')
        return value.strip()
    
    @staticmethod
    def validate_id(id_value):
        """Validate that an ID is safe."""
        if not isinstance(id_value, str):
            return False
        # IDs should be alphanumeric with optional hyphens/underscores
        return bool(re.match(r'^[a-zA-Z0-9_-]{1,50}$', id_value))
    
    @staticmethod
    def validate_pagination(first=None, offset=None):
        """Validate pagination parameters."""
        max_page_size = 50
        if first is not None:
            if not isinstance(first, int) or first < 1 or first > max_page_size:
                return False, f"'first' must be between 1 and {max_page_size}"
        if offset is not None:
            if not isinstance(offset, int) or offset < 0:
                return False, "'offset' must be a non-negative integer"
        return True, None


