class ProductType(graphene.ObjectType):
    """A product in the catalog."""
    id = graphene.ID(required=True)
    name = graphene.String(required=True)
    description = graphene.String()
    price = graphene.Float(required=True)
    in_stock = graphene.Boolean(required=True)
    sku = graphene.String(required=True)
    category = graphene.Field(CategoryType)
    reviews = graphene.List(ReviewType, first=graphene.Int(), offset=graphene.Int())
    average_rating = graphene.Float()
    review_count = graphene.Int()
    
    def resolve_category(self, info):
        cat_data = CATEGORIES.get(self.category_id)
        if cat_data:
            return CategoryType(**cat_data)
        return None
    
    def resolve_reviews(self, info, first=None, offset=None):
        valid, error = InputSanitizer.validate_pagination(first, offset)
        if not valid:
            raise GraphQLError(error)
        
        reviews = [
            ReviewType(**r) for r in REVIEWS.values()
            if r["product_id"] == self.id
        ]
        
        if offset:
            reviews = reviews[offset:]
        if first:
            reviews = reviews[:first]
        
        return reviews
    
    def resolve_average_rating(self, info):
        ratings = [
            r["rating"] for r in REVIEWS.values()
            if r["product_id"] == self.id
        ]
        if not ratings:
            return None
        return round(sum(ratings) / len(ratings), 2)
    
    def resolve_review_count(self, info):
        return sum(1 for r in REVIEWS.values() if r["product_id"] == self.id)


def _make_product(data):
    """Create a ProductType from raw data, storing category_id for lazy resolution."""
    pt = ProductType(
        id=data["id"],
        name=data["name"],
        description=data["description"],
        price=data["price"],
        in_stock=data["in_stock"],
        sku=data["sku"],
    )
    pt.category_id = data["category_id"]
    return pt


