class Query(graphene.ObjectType):
    """Root query type for the product catalog API."""
    
    # Single item queries
    product = graphene.Field(
        ProductType,
        id=graphene.ID(required=True),
        description="Fetch a single product by ID"
    )
    category = graphene.Field(
        CategoryType,
        id=graphene.ID(required=True),
        description="Fetch a single category by ID"
    )
    review = graphene.Field(
        ReviewType,
        id=graphene.ID(required=True),
        description="Fetch a single review by ID"
    )
    
    # Collection queries with pagination
    all_products = graphene.Field(
        ProductConnection,
        first=graphene.Int(default_value=10),
        offset=graphene.Int(default_value=0),
        in_stock_only=graphene.Boolean(default_value=False),
        description="Fetch all products with pagination"
    )
    all_categories = graphene.List(
        CategoryType,
        description="Fetch all categories"
    )
    all_reviews = graphene.Field(
        ReviewConnection,
        first=graphene.Int(default_value=10),
        offset=graphene.Int(default_value=0),
        min_rating=graphene.Int(),
        description="Fetch all reviews with optional filters"
    )
    
    # Filtered queries
    products_by_category = graphene.Field(
        ProductConnection,
        category_id=graphene.ID(required=True),
        first=graphene.Int(default_value=10),
        offset=graphene.Int(default_value=0),
        description="Fetch products by category"
    )
    reviews_by_product = graphene.Field(
        ReviewConnection,
        product_id=graphene.ID(required=True),
        first=graphene.Int(default_value=10),
        offset=graphene.Int(default_value=0),
        description="Fetch reviews for a specific product"
    )
    
    # Search
    search_products = graphene.Field(
        ProductConnection,
        query=graphene.String(required=True),
        first=graphene.Int(default_value=10),
        offset=graphene.Int(default_value=0),
        description="Search products by name or description"
    )
    
    # --- Resolvers ---
    
    def resolve_product(self, info, id):
        if not InputSanitizer.validate_id(id):
            raise GraphQLError("Invalid product ID format")
        data = PRODUCTS.get(id)
        if not data:
            return None
        return _make_product(data)
    
    def resolve_category(self, info, id):
        if not InputSanitizer.validate_id(id):
            raise GraphQLError("Invalid category ID format")
        data = CATEGORIES.get(id)
        if data:
            return CategoryType(**data)
        return None
    
    def resolve_review(self, info, id):
        if not InputSanitizer.validate_id(id):
            raise GraphQLError("Invalid review ID format")
        data = REVIEWS.get(id)
        if data:
            return ReviewType(**data)
        return None
    
    def resolve_all_products(self, info, first=10, offset=0, in_stock_only=False):
        valid, error = InputSanitizer.validate_pagination(first, offset)
        if not valid:
            raise GraphQLError(error)
        
        products = list(PRODUCTS.values())
        if in_stock_only:
            products = [p for p in products if p["in_stock"]]
        
        total = len(products)
        paginated = products[offset:offset + first]
        
        return ProductConnection(
            items=[_make_product(p) for p in paginated],
            total_count=total,
            has_next_page=(offset + first) < total
        )
    
    def resolve_all_categories(self, info):
        return [CategoryType(**c) for c in CATEGORIES.values()]
    
    def resolve_all_reviews(self, info, first=10, offset=0, min_rating=None):
        valid, error = InputSanitizer.validate_pagination(first, offset)
        if not valid:
            raise GraphQLError(error)
        
        reviews = list(REVIEWS.values())
        if min_rating is not None:
            if not (1 <= min_rating <= 5):
                raise GraphQLError("min_rating must be between 1 and 5")
            reviews = [r for r in reviews if r["rating"] >= min_rating]
        
        total = len(reviews)
        paginated = reviews[offset:offset + first]
        
        return ReviewConnection(
            items=[ReviewType(**r) for r in paginated],
            total_count=total,
            has_next_page=(offset + first) < total
        )
    
    def resolve_products_by_category(self, info, category_id, first=10, offset=0):
        if not InputSanitizer.validate_id(category_id):
            raise GraphQLError("Invalid category ID format")
        valid, error = InputSanitizer.validate_pagination(first, offset)
        if not valid:
            raise GraphQLError(error)
        
        if category_id not in CATEGORIES:
            raise GraphQLError("Category not found")
        
        products = [p for p in PRODUCTS.values() if p["category_id"] == category_id]
        total = len(products)
        paginated = products[offset:offset + first]
        
        return ProductConnection(
            items=[_make_product(p) for p in paginated],
            total_count=total,
            has_next_page=(offset + first) < total
        )
    
    def resolve_reviews_by_product(self, info, product_id, first=10, offset=0):
        if not InputSanitizer.validate_id(product_id):
            raise GraphQLError("Invalid product ID format")
        valid, error = InputSanitizer.validate_pagination(first, offset)
        if not valid:
            raise GraphQLError(error)
        
        if product_id not in PRODUCTS:
            raise GraphQLError("Product not found")
        
        reviews = [r for r in REVIEWS.values() if r["product_id"] == product_id]
        total = len(reviews)
        paginated = reviews[offset:offset + first]
        
        return ReviewConnection(
            items=[ReviewType(**r) for r in paginated],
            total_count=total,
            has_next_page=(offset + first) < total
        )
    
    def resolve_search_products(self, info, query, first=10, offset=0):
        sanitized_query = InputSanitizer.sanitize_string(query, max_length=100)
        if not sanitized_query or len(sanitized_query) < 2:
            raise GraphQLError("Search query must be at least 2 characters")
        
        valid, error = InputSanitizer.validate_pagination(first, offset)
        if not valid:
            raise GraphQLError(error)
        
        search_lower = sanitized_query.lower()
        results = [
            p for p in PRODUCTS.values()
            if search_lower in p["name"].lower() or search_lower in p["description"].lower()
        ]
        
        total = len(results)
        paginated = results[offset:offset + first]
        
        return ProductConnection(
            items=[_make_product(p) for p in paginated],
            total_count=total,
            has_next_page=(offset + first) < total
        )


