def create_app(config=None):
    """Application factory."""
    app = Flask(__name__)
    
    app_config = config or Config()
    app.config.from_object(app_config)
    
    query_validator = QueryValidator(app_config)
    
    def get_client_id():
        """Get a client identifier for rate limiting."""
        # Use X-Forwarded-For if behind a proxy, otherwise remote_addr
        forwarded = request.headers.get('X-Forwarded-For', '')
        if forwarded:
            # Take the first IP (client IP)
            ip = forwarded.split(',')[0].strip()
        else:
            ip = request.remote_addr or 'unknown'
        # Hash the IP for privacy
        return hashlib.sha256(ip.encode()).hexdigest()[:16]
    
    @app.before_request
    def security_checks():
        """Pre-request security middleware."""
        # Only apply to GraphQL endpoint
        if request.path != '/graphql':
            return
        
        # Rate limiting
        client_id = get_client_id()
        if rate_limiter.is_rate_limited(
            client_id,
            app_config.RATE_LIMIT_MAX_REQUESTS,
            app_config.RATE_LIMIT_WINDOW
        ):
            remaining = rate_limiter.get_remaining(
                client_id,
                app_config.RATE_LIMIT_MAX_REQUESTS,
                app_config.RATE_LIMIT_WINDOW
            )
            logger.warning(f"Rate limit exceeded for client {client_id}")
            return jsonify({
                "errors": [{"message": "Rate limit exceeded. Please try again later."}]
            }), 429
        
        # Store client_id for response headers
        g.client_id = client_id
    
    @app.after_request
    def add_security_headers(response):
        """Add security headers to all responses."""
        response.headers['X-Content-Type-Options'] = 'nosniff'
        response.headers['X-Frame-Options'] = 'DENY'
        response.headers['X-XSS-Protection'] = '1; mode=block'
        response.headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains'
        response.headers['Content-Security-Policy'] = "default-src 'none'"
        response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
        response.headers['Pragma'] = 'no-cache'
        
        # CORS headers
        origin = request.headers.get('Origin', '')
        if origin in app_config.ALLOWED_ORIGINS:
            response.headers['Access-Control-Allow-Origin'] = origin
            response.headers['Access-Control-Allow-Methods'] = 'POST, OPTIONS'
            response.headers['Access-Control-Allow-Headers'] = 'Content-Type, Authorization'
            response.headers['Access-Control-Max-Age'] = '3600'
        
        # Rate limit headers
        if hasattr(g, 'client_id'):
            remaining = rate_limiter.get_remaining(
                g.client_id,
                app_config.RATE_LIMIT_MAX_REQUESTS,
                app_config.RATE_LIMIT_WINDOW
            )
            response.headers['X-RateLimit-Limit'] = str(app_config.RATE_LIMIT_MAX_REQUESTS)
            response.headers['X-RateLimit-Remaining'] = str(remaining)
            response.headers['X-RateLimit-Window'] = str(app_config.RATE_LIMIT_WINDOW)
        
        return response
    
    @app.route('/graphql', methods=['POST'])
    def graphql_endpoint():
        """Main GraphQL endpoint - POST only for security."""
        # Validate content type
        content_type = request.content_type or ''
        if 'application/json' not in content_type:
            return jsonify({
                "errors": [{"message": "Content-Type must be application/json"}]
            }), 415
        
        # Parse request body
        try:
            data = request.get_json(force=False, silent=False)
        except Exception:
            return jsonify({
                "errors": [{"message": "Invalid JSON in request body"}]
            }), 400
        
        if not data or not isinstance(data, dict):
            return jsonify({
                "errors": [{"message": "Request body must be a JSON object"}]
            }), 400
        
        query = data.get('query', '')
        variables = data.get('variables') or {}
        operation_name = data.get('operationName')
        
        # Validate variables is a dict
        if not isinstance(variables, dict):
            return jsonify({
                "errors": [{"message": "Variables must be a JSON object"}]
            }), 400
        
        # Sanitize operation name
        if operation_name is not None:
            operation_name = InputSanitizer.sanitize_string(str(operation_name), max_length=100)
        
        # Run query validation
        is_valid, error_message = query_validator.validate(query)
        if not is_valid:
            logger.warning(f"Query validation failed: {error_message}")
            return jsonify({
                "errors": [{"message": error_message}]
            }), 400
        
        # Check complexity
        complexity = ComplexityAnalyzer.calculate_complexity(query)
        if complexity > app_config.GRAPHQL_MAX_COMPLEXITY:
            logger.warning(f"Query complexity {complexity} exceeds limit {app_config.GRAPHQL_MAX_COMPLEXITY}")
            return jsonify({
                "errors": [{"message": f"Query complexity ({complexity}) exceeds maximum allowed ({app_config.GRAPHQL_MAX_COMPLEXITY})"}]
            }), 400
        
        # Execute query
        try:
            result = schema.execute(
                query,
                variables=variables,
                operation_name=operation_name,
                context_value={
                    'request': request,
                }
            )
        except Exception as e:
            logger.error(f"GraphQL execution error: {str(e)}")
            return jsonify({
                "errors": [{"message": "Internal server error"}]
            }), 500
        
        # Build response
        response_data = {}
        
        if result.data:
            response_data['data'] = result.data
        
        if result.errors:
            response_data['errors'] = []
            for error in result.errors:
                # Sanitize error messages to avoid leaking internal details
                error_dict = {"message": str(error.message) if hasattr(error, 'message') else "An error occurred"}
                if hasattr(error, 'locations') and error.locations:
                    error_dict['locations'] = [
                        {"line": loc.line, "column": loc.column}
                        for loc in error.locations
                    ]
                if hasattr(error, 'path') and error.path:
                    error_dict['path'] = error.path
                response_data['errors'] = response_data.get('errors', [])
                response_data['errors'].append(error_dict)
        
        status_code = 200 if not result.errors else 200  # GraphQL returns 200 even with errors per spec
        return jsonify(response_data), status_code
    
    @app.route('/graphql', methods=['OPTIONS'])
    def graphql_options():
        """Handle CORS preflight requests."""
        return '', 204
    
    @app.route('/graphql', methods=['GET'])
    def graphql_get_not_allowed():
        """Reject GET requests to prevent CSRF and query logging in URLs."""
        return jsonify({
            "errors": [{"message": "GET method not allowed. Use POST with Content-Type: application/json"}]
        }), 405
    
    @app.route('/health', methods=['GET'])
    def health_check():
        """Health check endpoint."""
        return jsonify({"status": "healthy", "service": "product-catalog-api"}), 200
    
    return app


