    logger.info(f"Max query depth: {Config.GRAPHQL_MAX_DEPTH}")
    logger.info(f"Max query complexity: {Config.GRAPHQL_MAX_COMPLEXITY}")
    logger.info(f"Rate limit: {Config.RATE_LIMIT_MAX_REQUESTS} requests per {Config.RATE_LIMIT_WINDOW}s")
    
    # In production, use a proper WSGI server like gunicorn
